# This script starts a local FTP server for testing the `<export-script>` post-session action.
#
# Purpose:
# - Provides a minimal FTP endpoint that the Python upload client (e.g. AnonymousFTPClient)
#   can connect to during development and testing.
# - Allows verification that files generated by LabBench (e.g. via export-to-csv)
#   are correctly uploaded by the script action.
#
# Behavior:
# - Creates a directory at ~/Documents/ftp_server if it does not already exist.
# - Starts an FTP server on localhost (127.0.0.1) using the specified port (default: 2121).
# - Enables anonymous login with full permissions (read/write/delete).
# - Stores all uploaded files in the ftp_server directory.
#
# Usage in LabBench workflow:
# - The `<export-script>` action uploads files using FTP to this server.
# - The upload target (host=127.0.0.1, port=2121) must match the configuration
#   used in the Python client (e.g. CreateUploader).
# - After running an experiment, uploaded files can be inspected in the ftp_server folder.
#
# Notes:
# - Intended for local testing only. Not suitable for production use.
# - Requires `pyftpdlib`.

from pyftpdlib.authorizers import DummyAuthorizer
from pyftpdlib.handlers import FTPHandler
from pyftpdlib.servers import FTPServer

from pathlib import Path


def get_default_ftp_root():
    # Resolve "Documents/ftp_server" in a cross-platform way
    documents = Path.home() / "Documents"
    ftp_root = documents / "ftp_server"

    # Ensure directory exists
    ftp_root.mkdir(parents=True, exist_ok=True)

    return ftp_root


def start_ftp_server(port=2121):
    root_dir = get_default_ftp_root()

    authorizer = DummyAuthorizer()

    # Anonymous user with full permissions
    authorizer.add_anonymous(str(root_dir), perm="elradfmw")

    handler = FTPHandler
    handler.authorizer = authorizer

    server = FTPServer(("127.0.0.1", port), handler)

    print("=" * 50)
    print("FTP SERVER STARTED")
    print("=" * 50)
    print(f"Address:        ftp://127.0.0.1:{port}")
    print(f"Root directory: {root_dir}")
    print("Permissions:    anonymous (full access)")
    print("")
    print("Uploaded files will appear here:")
    print(f"  {root_dir}")
    print("")
    print("Press CTRL+C (or stop the process) to stop the server.")
    print("=" * 50)

    server.serve_forever()


if __name__ == "__main__":
    start_ftp_server()